args.script:
const editor = document.getElementById('editor');
const preview = document.getElementById('preview');
const status = document.getElementById('status');
const charCount = document.getElementById('char-count');
const tabEdit = document.getElementById('tab-edit');
const tabPreview = document.getElementById('tab-preview');

let saveTimeout = null;
const STORAGE_KEY = 'stuard_quick_notes';

// Load saved notes
editor.value = localStorage.getItem(STORAGE_KEY) || '';
updateCharCount();

// Simple markdown parser
function parseMarkdown(text) {
  return text
    .replace(/^### (.*$)/gm, '<h3>$1</h3>')
    .replace(/^## (.*$)/gm, '<h2>$1</h2>')
    .replace(/^# (.*$)/gm, '<h1>$1</h1>')
    .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
    .replace(/\*(.+?)\*/g, '<em>$1</em>')
    .replace(/`([^`]+)`/g, '<code>$1</code>')
    .replace(/^> (.*$)/gm, '<blockquote>$1</blockquote>')
    .replace(/^- (.*$)/gm, '<li>$1</li>')
    .replace(/(<li>.*<\/li>)/s, '<ul>$1</ul>')
    .replace(/\n/g, '<br>');
}

function updateCharCount() {
  charCount.textContent = `${editor.value.length} chars`;
}

function autoSave() {
  clearTimeout(saveTimeout);
  status.textContent = 'Saving...';
  saveTimeout = setTimeout(() => {
    localStorage.setItem(STORAGE_KEY, editor.value);
    status.textContent = 'Saved';
    setTimeout(() => status.textContent = 'Ready', 1000);
  }, 500);
}

// Editor events
editor.addEventListener('input', () => {
  updateCharCount();
  autoSave();
});

// Tab switching
tabEdit.addEventListener('click', () => {
  editor.classList.remove('hidden');
  preview.classList.add('hidden');
  tabEdit.classList.add('text-indigo-400', 'border-indigo-400');
  tabEdit.classList.remove('text-slate-400', 'border-transparent');
  tabPreview.classList.remove('text-indigo-400', 'border-indigo-400');
  tabPreview.classList.add('text-slate-400', 'border-transparent');
  editor.focus();
});

tabPreview.addEventListener('click', () => {
  editor.classList.add('hidden');
  preview.classList.remove('hidden');
  preview.innerHTML = parseMarkdown(editor.value) || '<span class="text-slate-500">Nothing to preview</span>';
  tabPreview.classList.add('text-indigo-400', 'border-indigo-400');
  tabPreview.classList.remove('text-slate-400', 'border-transparent');
  tabEdit.classList.remove('text-indigo-400', 'border-indigo-400');
  tabEdit.classList.add('text-slate-400', 'border-transparent');
});

// Action buttons
document.getElementById('btn-clear').addEventListener('click', () => {
  if (confirm('Clear all notes?')) {
    editor.value = '';
    localStorage.removeItem(STORAGE_KEY);
    updateCharCount();
    status.textContent = 'Cleared';
  }
});

document.getElementById('btn-copy').addEventListener('click', async () => {
  await stuard.copyToClipboard(editor.value);
  status.textContent = 'Copied!';
  setTimeout(() => status.textContent = 'Ready', 1000);
});

document.getElementById('btn-save').addEventListener('click', async () => {
  const result = await stuard.pickSavePath({
    title: 'Save Notes',
    defaultPath: 'notes.md',
    filters: [{ name: 'Markdown', extensions: ['md'] }, { name: 'Text', extensions: ['txt'] }]
  });

  if (!result.canceled && result.filePath) {
    try {
      await stuard.writeFile(result.filePath, editor.value);
      status.textContent = 'Saved to file!';
      stuard.notify('Notes Saved', result.filePath);
    } catch (e) {
      status.textContent = 'Save failed';
    }
  }
});

// Keyboard shortcuts
editor.addEventListener('keydown', (e) => {
  if (e.ctrlKey && e.key === 's') {
    e.preventDefault();
    document.getElementById('btn-save').click();
  }
});

editor.focus();
